#ifndef nsCSPParser_h_
#define nsCSPParser_h_

#include "PolicyTokenizer.h"
#include "nsCSPContext.h"
#include "nsCSPUtils.h"
#include "nsIURI.h"

bool isNumberToken(char16_t aSymbol);
